INSERT INTO `sys_announcement` (`id`, `title`, `content`, `type`, `is_top`, `start_time`, `end_time`, `status`, `created_at`, `updated_at`) VALUES (1,'知讯平台正式上线公告','亲爱的用户，知讯平台于2026年6月23日正式上线！我们致力于打造一个优质的内容社区，让每一篇好文章都被发现，让每一个创作者都被看见。欢迎大家注册体验，分享你的知识和见解！',1,1,'2026-06-23 00:00:00','2026-12-31 23:59:59',1,'2026-06-23 00:00:00','2026-06-23 00:00:00'),(2,'内容创作者招募计划','知讯现面向全网招募优质内容创作者！无论你是技术大牛、行业专家、还是生活达人，只要你有优质内容，我们都欢迎你加入。优质创作者可享受流量扶持、专属推荐位等权益。详情请联系运营小编。',2,0,'2026-06-23 00:00:00','2026-09-30 23:59:59',1,'2026-06-23 00:00:00','2026-06-23 00:00:00'),(3,'社区规范公告','为维护知讯社区的良好氛围，请各位用户遵守以下规范：1. 尊重他人，文明交流；2. 不发布违法违规内容；3. 不恶意刷屏或灌水；4. 不抄袭他人作品；5. 积极举报不良内容。让我们共同维护一个健康、友善的内容社区。',1,0,'2026-06-23 00:00:00','2027-06-23 23:59:59',1,'2026-06-23 00:00:00','2026-06-23 00:00:00');
/*!40000 ALTER TABLE `sys_announcement` ENABLE KEYS */;
