INSERT INTO `user_message` (`id`, `sender_id`, `receiver_id`, `content`, `is_read`, `created_at`) VALUES (1,11,3,'代码匠人你好，你的Spring Boot微服务文章写得太好了，请问有推荐的入门书籍吗？',1,'2026-02-12 09:00:00'),(2,3,11,'谢谢！推荐《Spring微服务实战》和《领域驱动设计》，先从概念理解开始',1,'2026-02-12 10:30:00'),(3,11,4,'AI前沿实验室，你们团队在用哪个LLM做RAG？想交流一下',1,'2026-04-07 14:00:00'),(4,4,11,'我们用的是Qwen2.5-72B做基座，配合bge-large-zh做embedding，效果不错',1,'2026-04-07 15:00:00'),(5,12,9,'创业笔记，看了你的PMF文章很受启发，能聊聊你们第一次失败的具体经历吗？',1,'2026-02-10 08:00:00'),(6,9,12,'当然可以，简单说就是花了6个月做了一个\"完美\"的产品，但没人用。核心教训是先验证需求再开发',1,'2026-02-10 09:30:00'),(7,15,7,'行走的镜头，京都的攻略太详细了！请问住宿有什么推荐吗？',1,'2026-05-12 08:00:00'),(8,7,15,'推荐住在四条河原町附近，交通方便，去哪里都近。预算够的话可以选京都站附近的酒店',1,'2026-05-12 10:00:00'),(9,14,8,'味蕾探险家，成都美食地图太实用了，冒椒火辣我也去过，确实好吃！',1,'2026-06-18 14:00:00'),(10,8,14,'哈哈对吧！下次去可以试试建设路的夜市，更多小吃',1,'2026-06-18 15:00:00'),(11,11,5,'前端小仙女，请问Nuxt 3和Next.js 15怎么选？我们团队在纠结',1,'2026-01-22 08:00:00'),(12,5,11,'看团队技术栈，如果熟悉Vue就Nuxt，熟悉React就Next。两者功能上差别不大了',1,'2026-01-22 09:00:00'),(13,13,4,'关于量子计算的文章写得很好，请问量子退相干目前有什么解决方案吗？',0,'2026-02-17 08:00:00'),(14,6,10,'设计达人，最近在学设计思维，有什么推荐的课程吗？',1,'2026-06-14 08:00:00'),(15,10,6,'推荐IDEO的在线课程和《设计思维》这本书，理论和实践结合得很好',1,'2026-06-14 10:00:00'),(16,1,23,'',0,'2026-06-26 14:53:42');
/*!40000 ALTER TABLE `user_message` ENABLE KEYS */;
